declare i32 @strcmp(ptr, ptr)

define i32 @call_strcmp_a5i0_a5i1_pI(i64 %I) {
  %q = getelementptr [5 x [4 x i8]], ptr @a5, i64 0, i64 1, i64 %I
  %cmp = call i32 @strcmp(ptr @a5, ptr %q)
  ret i32 %cmp
}

